function Dots({ current }) {
  return (
    <div className="sq-dots">
      {[0, 1, 2, 3].map((i) => (
        <div key={i} className={`sq-dot${i < current ? " done" : i === current ? " cur" : ""}`} />
      ))}
    </div>
  );
}

export default function SideQuestGenerator() {
  const [step, setStep] = useState(0);
  const [answers, setAnswers] = useState({});
  const [freetext, setFreetext] = useState("");
  const [loadMsg, setLoadMsg] = useState(LOAD_MSGS[0]);
  const [quest, setQuest] = useState(null);
  const [error, setError] = useState(null);
  const [showShare, setShowShare] = useState(false);
  const [copied, setCopied] = useState(false);

  const select = (qi, val) => setAnswers((a) => ({ ...a, [qi]: val }));

  const generateQuest = async () => {
    setError(null);
    setQuest(null);
    setStep(4);

    let mi = 0;
    const iv = setInterval(() => {
      mi = (mi + 1) % LOAD_MSGS.length;
      setLoadMsg(LOAD_MSGS[mi]);
    }, 1600);

    const prompt = `Tu es un générateur de side quests pour la vraie vie, conçu pour des femmes entrepreneures. Ton ton : direct, bienveillant, sans condescendance. Pas de motivational speech vague. Du concret.

Profil :
- Situation business : ${answers[0]}
- Ce qui la retient : ${answers[1]}
- Temps disponible : ${answers[2]}
- Ce qu'elle veut oser : ${freetext}

Public : femmes entrepreneures, bosseuses, perfectionnistes, un peu timides sur la visibilité mais ambitieuses. La quête doit les pousser légèrement hors de leur zone de confort, pas un grand saut, mais une action concrète qui crée du mouvement réel.

Réponds UNIQUEMENT avec un objet JSON valide. Pas de texte avant, pas de texte après, pas de backticks :
{"name":"Titre accrocheur 6 mots max","description":"2 phrases style journal de bord ton direct","objectives":["action concrète 1","action concrète 2","action concrète 3"],"reward":"Ce qu elle gagne en 1 phrase directe"}`;

    try {
      const resp = await fetch("/api/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt }),
      });

      const data = await resp.json();
      if (data.error) throw new Error(data.error.message);

      const raw = data.content.filter((b) => b.type === "text").map((b) => b.text).join("");
      const si = raw.indexOf("{");
      const ei = raw.lastIndexOf("}");
      if (si === -1) throw new Error("Réponse inattendue : " + raw.slice(0, 120));
      const parsed = JSON.parse(raw.slice(si, ei + 1));

      clearInterval(iv);
      setQuest(parsed);
      setStep(5);
    } catch (e) {
      clearInterval(iv);
      setError(e.message);
      setStep(5);
    }
  };

  const shareText = quest
    ? `✦ Ma Side Quest du jour\n\n${quest.name}\n\n${quest.description}\n\n→ ${quest.objectives.join("\n→ ")}\n\n Ce que je gagne : ${quest.reward}\n\n#SideQuest #Entropie #FemmeEntrepreneuse`
    : "";

  const copyShare = async () => {
    try {
      await navigator.clipboard.writeText(shareText);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {}
  };

  const restart = () => {
    setStep(0);
    setAnswers({});
    setFreetext("");
    setQuest(null);
    setError(null);
    setShowShare(false);
    setCopied(false);
  };

  return (
    <>
      <style>{css}</style>
      <div className="sq-wrap">

        <div className="sq-hero">
          <div style={{display:"flex", alignItems:"center", gap:"16px"}}>
            <img src={LOGO_B64} alt="Entropie" style={{width:"48px", height:"48px", objectFit:"contain", mixBlendMode:"screen"}} />
            <div>
              <div className="sq-hero-title">Side Quest Generator</div>
              <div className="sq-hero-eyebrow" style={{textTransform:"none", letterSpacing:"1px", fontWeight:500, opacity:1}}>by Entropie</div>
            </div>
          </div>
        </div>

        <div className="sq-body">

          {step === 0 && (
            <div>
              <div className="sq-example">
                <div className="sq-ex-label">C'est quoi ?</div>
                <div className="sq-ex-text">Une quête concrète, générée pour toi, pour sortir de ta zone de confort sans te perdre. Pas un grand saut, juste une action qui crée du mouvement.</div>
              </div>
              <div className="sq-qnum">Question 01 / 04</div>
              <div className="sq-qtext">{QUESTIONS[0].text}</div>
              <div className="sq-qsub">{QUESTIONS[0].sub}</div>
              <div className="sq-choices">
                {QUESTIONS[0].choices.map((c) => (
                  <button key={c} className={`sq-choice${answers[0] === c ? " sel" : ""}`} onClick={() => select(0, c)}>{c}</button>
                ))}
              </div>
              <div className="sq-row">
                <Dots current={0} />
                <button className="sq-next" disabled={!answers[0]} onClick={() => setStep(1)}>Continuer</button>
              </div>
            </div>
          )}

          {step === 1 && (
            <div>
              <div className="sq-qnum">Question 02 / 04</div>
              <div className="sq-qtext">{QUESTIONS[1].text}</div>
              <div className="sq-qsub">{QUESTIONS[1].sub}</div>
              <div className="sq-choices">
                {QUESTIONS[1].choices.map((c) => (
                  <button key={c} className={`sq-choice${answers[1] === c ? " sel" : ""}`} onClick={() => select(1, c)}>{c}</button>
                ))}
              </div>
              <div className="sq-row">
                <button className="sq-back" onClick={() => setStep(0)}>← Retour</button>
                <Dots current={1} />
                <button className="sq-next" disabled={!answers[1]} onClick={() => setStep(2)}>Continuer</button>
              </div>
            </div>
          )}

          {step === 2 && (
            <div>
              <div className="sq-qnum">Question 03 / 04</div>
              <div className="sq-qtext">{QUESTIONS[2].text}</div>
              <div className="sq-qsub">{QUESTIONS[2].sub}</div>
              <div className="sq-choices">
                {QUESTIONS[2].choices.map((c) => (
                  <button key={c} className={`sq-choice${answers[2] === c ? " sel" : ""}`} onClick={() => select(2, c)}>{c}</button>
                ))}
              </div>
              <div className="sq-row">
                <button className="sq-back" onClick={() => setStep(1)}>← Retour</button>
                <Dots current={2} />
                <button className="sq-next" disabled={!answers[2]} onClick={() => setStep(3)}>Continuer</button>
              </div>
            </div>
          )}

          {step === 3 && (
            <div>
              <div className="sq-qnum">Question 04 / 04</div>
              <div className="sq-qtext">S'il y avait une chose que tu voulais oser mais que tu repousses, ce serait quoi ?</div>
              <div className="sq-qsub">Même si c'est flou, écris ce qui vient.</div>
              <textarea
                className="sq-textarea"
                value={freetext}
                onChange={(e) => setFreetext(e.target.value)}
                placeholder="ex: parler en public, poster sur les réseaux, aller à un événement networking..."
              />
              <div className="sq-row">
                <button className="sq-back" onClick={() => setStep(2)}>← Retour</button>
                <Dots current={3} />
                <button className="sq-next" disabled={freetext.trim().length < 3} onClick={generateQuest}>Révéler ma quête</button>
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="sq-load">
              <span className="sq-load-icon">✦</span>
              <div className="sq-load-label">{loadMsg}</div>
            </div>
          )}

          {step === 5 && (
            <div>
              {error && <div className="sq-error"><strong>Erreur :</strong> {error}</div>}
              {quest && (
                <div>
                  <div className="sq-rtag">Ta quête</div>
                  <div className="sq-rname">{quest.name}</div>
                  <div className="sq-rdesc">{quest.description}</div>
                  <div className="sq-divider" />
                  <div className="sq-olabel">Les étapes</div>
                  <ul className="sq-olist">
                    {quest.objectives.map((o, i) => (
                      <li key={i} className="sq-oitem">
                        <span className="sq-onum">0{i + 1}.</span>
                        <span>{o}</span>
                      </li>
                    ))}
                  </ul>
                  <div className="sq-reward">
                    <div className="sq-rlabel">Ce que tu gagnes</div>
                    <div className="sq-rtext">{quest.reward}</div>
                  </div>
                </div>
              )}
              <div className="sq-actions">
                {quest && <button className="sq-share-btn" onClick={() => setShowShare(!showShare)}>Partager</button>}
                <button className="sq-restart-btn" onClick={restart}>Nouvelle quête</button>
              </div>
              {showShare && quest && (
                <div className="sq-share-box">
                  <div className="sq-share-title">Copie et partage ta quête</div>
                  <textarea className="sq-share-ta" readOnly value={shareText} />
                  <button className={`sq-copy-btn${copied ? " copied" : ""}`} onClick={copyShare}>
                    {copied ? "✓ Copié !" : "Copier le texte"}
                  </button>
                </div>
              )}
            </div>
          )}

        </div>
      </div>
    </>
  );
}
